description:
کلاس پایه‌ای برای تمامی اشیاء و عناصر سه‌بعدی در موتور گودو. این نود وظیفه نگهداری و محاسبه داده‌های ترنسفورم محلی و جهانی را بر عهده داشته و متدهای حساسی همچون LookAt برای چرخش آنی به سمت هدف و ToGlobal/ToLocal جهت تبدیل پویای مختصات را ارائه می‌دهد.

C#:
Position = new Vector3(10.5f, 5.0f, -2.5f);

نود رندرکننده تصاویر دو بعدی در بستر یک جهان سه‌بعدی. این نود برای ساخت بازی‌های سبک 2.5D، افکت‌های بیلبورد و المان‌های دوبعدی محیطی کاربرد دارد و از انیمیشن‌های فریم به فریم و بافت‌های اطلس پشتیبانی می‌کند.

C#:
Texture = GD.Load<Texture2D>("res://assets/player_sprite.png");

نودی تخصصی هم‌خانواده با Sprite3D که رندر انیمیشن‌های فریم به فریم سنتی دوبعدی را در فضای سه‌بعدی بر عهده دارد. این نود با متد Play انیمیشن‌های منبع داده SpriteFrames را اجرا کرده و سیگنال‌های اتمام پخش را برای همگام‌سازی بازی صادر می‌نماید.

C#:
Play("run_animation");

نود استاندارد و اصلی برای وهله‌سازی و رندر مش‌ها و مدل‌های هندسی سه‌بعدی در صحنه بازی. این نود منابع مش را با متریال‌های تخصیص‌یافته روی صفحه ترسیم کرده و متدهایی نظیر CreateTrimeshCollision برای تولید خودکار شکل فیزیکی دقیق از روی مش بصری را داراست.

C#:
Mesh = new BoxMesh();

نود تخصصی بهینه‌سازی رندر که رندر سخت‌افزاری هزاران کپی هم‌شکل از یک مش را با ارسال یکباره دستور ترسیم به کارت گرافیک (Instancing) ممکن می‌سازد.

C#:
Multimesh.InstanceCount = 1000;

نود طراحی مراحل تایل‌بندی شده سه‌بعدی که به توسعه‌دهنده امکان می‌دهد با استفاده از یک کتابخانه مش (MeshLibrary) به صورت شبکه‌ای مراحل سه‌بعدی را سریعاً چیدمان و بهینه‌سازی کند.

C#:
SetCellItem(new Vector3I(1, 0, 1), item: 2, orientation: 0);

کلاس انتزاعی مرجع و پایه برای تمامی اشیاء و موجوداتی که نیازمند تعامل فیزیکی و تشخیص برخورد در فضای سه‌بعدی هستند. این نود لایه‌ها و ماسک‌های برخورد را تنظیم کرده و سیگنال‌های حساسی مانند کلیک‌های ورودی روی مدل را هندل می‌کند.

C#:
CollisionLayer = 1; CollisionMask = 1;

یک ناحیه برخورد سه‌بعدی غیرصلب که صرفاً برای پیاده‌سازی تریگرها، تشخیص هم‌پوشانی و ورود/خروج اجسام فیزیکی دیگر بکار می‌رود.

C#:
BodyEntered += (Node3D body) => GD.Print("شخصیت وارد ناحیه شد: " + body.Name);

کلاس انتزاعی واسط برای تمام بدنه‌های متحرک یا ایستایی که قرار است مستقیماً در محاسبات موتور فیزیک سه‌بعدی گودو مشارکت داشته باشند.

C#:
AddCollisionExceptionWith(GetNode<Node3D>("../OtherBody"));

نود تخصصی فیزیکی برای کاراکترهای تحت کنترل مستقیم اسکریپت یا هوش مصنوعی. این نود با متد MoveAndSlide و متغیر Velocity، جابه‌جایی روان در پله‌ها و برخورد با دیوارها را با بهینه‌ترین حالت پیاده‌سازی می‌کند.

C#:
Velocity = new Vector3(0, 0, -5f); MoveAndSlide();

نود بدنه صلب با فیزیک نیوتنی کامل که بر مبنای جرم، نیرو، گشتاور و نیروی جاذبه شبیه‌سازی می‌شود. ویرایش‌های داینامیک آن باید داخل متد مجازی _IntegrateForces هدایت گردد.

C#:
ApplyCentralImpulse(new Vector3(0f, 15f, 0f));

نود موانع فیزیکی کاملاً ثابت صحنه که توسط شبیه‌ساز فیزیک جابه‌جا نمی‌شوند. این نود ویژگی‌هایی نظیر اصطکاک را تعیین کرده و می‌تواند رفتارهایی نظیر نوار نقاله را شبیه‌سازی کند.

C#:
ConstantLinearVelocity = new Vector3(3f, 0f, 0f);

بدنه فیزیکی ویژه‌ای ارث‌بری شده از StaticBody3D مجهز به قابلیت جابه‌جایی با اسکریپت یا انیمیشن‌پلیر (مانند آسانسورها). این نود سرعت حرکتی خود را به اجسام متحرک سوار بر خود القا می‌کند.

C#:
SyncToPhysics = true;

نود پیونددهنده یک شکل ساده هندسی ریاضی به بدنه‌های فیزیکی والد جهت توصیف مرزهای برخورد آن‌ها برای موتور فیزیک.

C#:
GetNode<CollisionShape3D>("Collision").Disabled = false;

نود ایجاد برخورد فیزیکی سه‌بعدی منشورمانند که با تعمیم یک پولیگون دوبعدی در امتداد یک ارتفاع مشخص، اشکال برخورد سفارشی و منحصربه‌فردی را به بدنه‌ها اضافه می‌کند.

C#:
Depth = 2.5f;

نود پرتاب‌کننده خط مستقیم نامرئی در فضا جهت کوئری گرفتن آنی از وجود موانع فیزیکی. متد GetCollider برخوردکننده و متد GetCollisionPoint موقعیت برخورد را ارائه می‌دهند.

C#:
if (IsColliding()) { var hitNode = (Node3D)GetCollider(); }

نود پیشرفته پرتاب شکل که به جای یک خط باریک، یک محدوده حجمی سه‌بعدی هندسی سفارشی را در طول جهت تعریف‌شده جارو می‌کند تا تمامی اجسام متداخل را بلافاصله کشف کند.

C#:
ForceShapecastUpdate();

یک صلیب نشانه‌گذاری مختصاتی نامرئی در زمان اجرای بازی که صرفاً برای ثبت موقعیت‌های موقت و راهنمایی در محیط ادیتور نمایش داده می‌شود.

C#:
Vector2 position2D = GetViewport().GetCamera3D().UnprojectPosition(GlobalPosition);

نود نگهدارنده منحنی‌های پیچیده سه‌بعدی ریاضی برای ترسیم مسیر حرکت دوربین‌ها، قطارها و ایجاد بستر حرکت داینامیک برای دشمنان.

C#:
Curve.AddPoint(new Vector3(5f, 10f, 0f));

این نود باید فرزند Path3D باشد و با تغییر پارامتر پیشروی، نودهای فرزند خود را کاملاً روان روی منحنی والد حرکت می‌دهد.

C#:
ProgressRatio += 0.05f;

نود فرستنده جابه‌جایی که تغییرات موقعیت و چرخش خود را به صورت زنده به یک نود سه‌بعدی هدف دیگر پمپاژ می‌کند؛ بدون نیاز به رابطه والد-فرزندی مستقیم.

C#:
RemotePath = GetNode("../TargetMesh").GetPath();

نود ناظر بر محیط بازی که کادربندی نهایی و رندر دید سه‌بعدی را هندل می‌کند. این نود مدهای پرسپکتیو یا ارتوگرافیک را پوشش می‌دهد.

C#:
Fov = 75f;

بازوی منعطف مجهز به سیستم تشخیص مانع که دوربین سوم شخص را در صورت برخورد با موانع به جلو می‌کشد تا از نفوذ به داخل دیوارها جلوگیری شود.

C#:
SpringLength = 4.0f;

قلب تپنده تنظیمات گرافیکی پیشرفته. این نود کنترل نور محیطی، پس‌پردازش‌ها نظیر Bloom، آسمان‌نما و مه حجمی را انجام می‌دهد.

C#:
Environment.VolumetricFogEnabled = true;

منبع نوری همه‌سویه که پرتوهای نوری خود را به صورت کروی از مرکز به تمامی جهات ساطع می‌کند (مشابه لامپ).

C#:
LightEnergy = 2.5f; OmniRange = 10f;

منبع نوری بی‌نهایت دور که تابش مستقیم و کاملاً موازی پرتوها را بر کل جهان اعمال می‌سازد (مشابه خورشید).

C#:
LightColor = Colors.White; LightEnergy = 1.0f;

منبع نوری مخروطی که تابش پرتوها را در زاویه‌ای مشخص جهت می‌دهد (شبیه‌ساز چراغ قوه).

C#:
SpotAngle = 45f;

تصویرکننده بافت روی مش‌های سه‌بعدی بدون تغییر هندسه. برای آثاری نظیر لکه‌ها، رد گلوله یا خون روی دیوارها به کار می‌رود.

C#:
AlbedoMix = 0.8f;

تعریف محدوده حجمی برای تولید مه غلیظ محلی. این نود با متریال‌های تخصصی، ته‌مایه‌های رنگی مه برای صحنه‌هایی مثل تالاب ایجاد می‌کند.

C#:
Size = new Vector3(5f, 5f, 5f);

میکروفون نامرئی فضای سه‌بعدی که به دوربین بازی الصاق می‌شود تا موقعیت دریافت افکت‌های صوتی فضایی را مشخص کند.

C#:
MakeCurrent();

پخش‌کننده صوتی مجهز به محاسبات فاصله و جهت. این نود بلندی و پانینگ صدا را بر حسب فاصله تا شنونده تغییر می‌دهد.

C#:
Play();

شبیه‌ساز ذرات معلق که محاسبات را روی CPU انجام می‌دهد و سازگاری بالایی با دستگاه‌های مختلف دارد.

C#:
Emitting = true;

سیستم ذرات شتاب‌یافته گرافیکی که امکان رندر هزاران ذره فیزیکی را با توان کارت گرافیک فراهم می‌آورد.

C#:
Amount = 10000;

نگهدارنده سلسله‌مراتب استخوان‌بندی و ریگینگ انیمیشنی. این نود موقعیت استخوان‌ها را به متریال مش الصاق می‌کند.

C#:
int boneIndex = FindBone("Head_Bone");

اتصال‌دهنده آیتم‌ها به استخوان‌های Skeleton3D. برای الصاق سلاح، تجهیزات یا افکت به کاراکتر در حال حرکت کاربرد دارد.

C#:
BoneName = "Hand_R";

هوش مصنوعی ناوبری که با سرور ناوبری در ارتباط است تا بهترین مسیر حرکتی را برای کاراکترها محاسبه کند.

C#:
TargetPosition = enemyTarget.GlobalPosition;

کانتینر تجهیز صحنه‌ها به مش ناوبری. این نود سطوح قابل پیمایش را شناسایی می‌کند تا عامل‌های ناوبری مسیر را ردگیری کنند.

C#:
BakeNavigationMesh();
